        if not isinstance(population, (int, float)):
            raise ValueError("Invalid population: Population must be a number.")
        if population < 0:
            raise ValueError("Invalid population: Population cannot be negative.")

        population = math.floor(population)
        country_population_list.append({"Country": country, "Population": population})

    df = pd.DataFrame(country_population_list)

    file_path = os.path.join(output_dir, file_name)
    try:
        df.to_csv(file_path, index=False)
    except Exception as e:
        raise IOError(f"Could not write to file: {file_path}. Error: {e}")

    return file_path, df

