import json
import smtplib
SMTP_SERVER = "smtp.gmail.com"
SMTP_PORT = 587
EMAIL_ADDRESS = "your.email@gmail.com"
EMAIL_PASSWORD = "your.password"
def task_func(input_data=None, smtp_server=SMTP_SERVER, smtp_port=SMTP_PORT, email_address=EMAIL_ADDRESS, email_password=EMAIL_PASSWORD, smtp=None):
    if input_data is None:
        raise ValueError("Input data cannot be None")

    try:
        data = json.loads(input_data)
    except json.JSONDecodeError as e:
        raise ValueError("Invalid JSON input") from e

    extracted_names = []
    for entry in data:
        if "name" in entry and "email" in entry:
            extracted_names.append(entry["name"])

    subject = "Extracted Names"
    body = "\n".join(extracted_names)
    message = f"Subject: {subject}\n\n{body}"

    try:
        if smtp is None:
            smtp = smtplib.SMTP(smtp_server, smtp_port)
            smtp.starttls()
            smtp.login(email_address, email_password)

        smtp.sendmail(email_address, email_address, message)
    except Exception as e:
        raise RuntimeError("Failed to send email") from e
    finally:
        if smtp is not None:
            smtp.quit()

    return extracted_names

import random
import string
LETTERS = string.ascii_letters
DIGITS = string.digits
def task_func(length, num_digits):

    random.seed(42)
    if length <= 0:
        raise ValueError("Length must be a positive integer.")
    if not (0 <= num_digits <= length):
        raise ValueError("num_digits must be a non-negative integer and less than or equal to length.")

    password = []
    for _ in range(length - num_digits):
        password.append(random.choice(LETTERS))
    for _ in range(num_digits):
        password.append(random.choice(DIGITS))

    random.shuffle(password)

    return ''.join(password)

