import requests
from lxml import html
import pandas as pd
import sqlite3
def task_func(webpage_url: str, database_name: str = "my_database.db") -> int:
    try:
        if webpage_url.startswith("http://") or webpage_url.startswith("https://"):
            response = requests.get(webpage_url)
            response.raise_for_status()                                                  
            html_content = response.text
        else:                                 
            with open(webpage_url, 'r', encoding='utf-8') as f:
                html_content = f.read()

        tree = html.fromstring(html_content)
        table = tree.xpath('//table')

        if not table:
            return 0

        table = table[0]
        rows = table.xpath('.//tr')
        if not rows:
            return 0

        header = [th.text_content().strip() for th in rows[0].xpath('.//th')]
        if not header:
            header = [td.text_content().strip() for td in rows[0].xpath('.//td')]
        if not header:
            return 0

        data = []
        for row in rows[1:]:
            row_data = [td.text_content().strip() for td in row.xpath('.//td')]
            if len(row_data) == len(header):
                data.append(row_data)

        if not data:
            return 0

        df = pd.DataFrame(data, columns=header)

        conn = sqlite3.connect(database_name)
        df.to_sql("my_table", conn, if_exists="replace", index=False)
        conn.close()

        return len(df)

    except requests.RequestException as e:
        raise requests.RequestException(f"Error accessing URL: {e}")
    except sqlite3.DatabaseError as e:
        raise sqlite3.DatabaseError(f"Error accessing or writing to database: {e}")
    except Exception as e:
        raise Exception(f"An unexpected error occurred: {e}")

import requests
from lxml import html
import pandas as pd
import sqlite3
def task_func(webpage_url: str, database_name: str = "my_database.db") -> int:

    try:
        if webpage_url.startswith('file://'):
            with open(webpage_url[7:], 'r') as f:
                html_content = f.read()
        else:
            response = requests.get(webpage_url)
            response.raise_for_status()                                      
            html_content = response.text

        tree = html.fromstring(html_content)

        table = tree.xpath('//table')

        if not table:
            return 0

        df = pd.read_html(html.tostring(table[0], encoding='unicode'))[0]

        if df.empty:
            return 0

        with sqlite3.connect(database_name) as conn:
            df.to_sql('my_table', conn, if_exists='replace', index=False)

        return len(df)

    except requests.RequestException as e:
        raise requests.RequestException(f"Network issue: {e}")

    except sqlite3.DatabaseError as e:
        raise sqlite3.DatabaseError(f"Database issue: {e}")

import bs4
import requests
import re
import json
def task_func(url: str, output_path: str) -> list:
    def extract_phone_numbers(text):
        phone_regex = re.compile(r'\+?\d{1,3}[-.\s]?\(?\d{1,4}\)?[-.\s]?\d{1,4}[-.\s]?\d{1,9}')
        return phone_regex.findall(text)

    def fetch_content(source):
        if source.startswith("http://") or source.startswith("https://"):
            try:
                response = requests.get(source)
                response.raise_for_status()
                return response.text
            except requests.RequestException as e:
                print(f"Error fetching URL content: {e}")
                return ""
        else:
            try:
                with open(source, 'r', encoding='utf-8') as file:
                    return file.read()
            except FileNotFoundError as e:
                print(f"Error reading file: {e}")
                return ""

    content = fetch_content(url)
    if not content:
        return []

    soup = bs4.BeautifulSoup(content, 'html.parser')
    text = soup.get_text()

    phone_numbers = extract_phone_numbers(text)

    try:
        with open(output_path, 'w', encoding='utf-8') as output_file:
            json.dump(phone_numbers, output_file, indent=4)
    except IOError as e:
        print(f"Error writing to output file: {e}")
        return []

    return phone_numbers

