import statistics
import numpy as np
def task_func(input_list):

    if not input_list:
        return (None, None, None, None, None, None)

    sorted_list = sorted(input_list, key=lambda item: item[1])

    degree_values = [item[1] for item in sorted_list]

    try:
        mean_sorted = round(statistics.mean(degree_values))
    except statistics.StatisticsError:
        mean_sorted = None
    try:
        median_sorted = round(statistics.median(degree_values))
    except statistics.StatisticsError:
        median_sorted = None
    try:
        mode_sorted = round(statistics.mode(degree_values))
    except statistics.StatisticsError:
        mode_sorted = None

    fft_magnitude = np.abs(np.fft.fft(degree_values))
    fft_magnitude_int = [round(x) for x in fft_magnitude]

    try:
        mean_fft = round(statistics.mean(fft_magnitude_int))
    except statistics.StatisticsError:
        mean_fft = None
    try:
        median_fft = round(statistics.median(fft_magnitude_int))
    except statistics.StatisticsError:
        median_fft = None
    try:
        mode_fft = round(statistics.mode(fft_magnitude_int))
    except statistics.StatisticsError:
        mode_fft = None

    return (mean_sorted, median_sorted, mode_sorted, mean_fft, median_fft, mode_fft)

from collections import Counter
import hashlib
def task_func(word: str) -> dict:
    pairs = list(map(''.join, zip(word[:-1], word[1:])))
    pairs_count = dict(Counter(pairs))
    return hashlib.md5(str(pairs_count).encode()).hexdigest()

