import os
import shutil
BACKUP_DIR = '/tmp/backup'
def task_func(directory):
    if not os.path.exists(BACKUP_DIR):
        return f"Backup directory {BACKUP_DIR} does not exist. Cannot rollback update."

    backup_target = os.path.join(BACKUP_DIR, os.path.basename(directory))
    if not os.path.exists(backup_target):
        return f"Backup for {directory} not found in {BACKUP_DIR}. Cannot rollback update."

    try:
        if os.path.exists(directory):
            if os.path.isdir(directory):
                shutil.rmtree(directory)
            else:
                os.remove(directory)
        shutil.copytree(backup_target, directory)
        return directory
    except Exception as e:
        return f"Error during rollback: {e}"

