import sqlite3
import pandas as pd
import os
import re
def task_func(db_file, table_name, column_name, pattern='\d+[xX]'):
    if not os.path.exists(db_file):
        raise ValueError(f"Database file not found: {db_file}")

    conn = None
    try:
        conn = sqlite3.connect(db_file)
        query = f"SELECT {column_name} FROM {table_name}"
        df = pd.read_sql_query(query, conn)

        matches = []
        for index, row in df.iterrows():
            text = row[column_name]
            if isinstance(text, str):
                found_matches = re.findall(pattern, text)
                for match in found_matches:
                    matches.append({'index': index, 'match': match})

        return pd.DataFrame(matches)

    finally:
        if conn:
            conn.close()

import numpy as np
import itertools
import random
import statistics
def task_func(T1, RANGE=100):
    if not T1:
        raise statistics.StatisticsError("T1 is empty. Cannot proceed with an empty list.")

    try:
        T1_integers = list(map(int, T1))
    except ValueError as e:
        raise ValueError("All elements in T1 must be convertible to integers.") from e

    list_size = sum(T1_integers)

    if list_size <= 0:
        raise statistics.StatisticsError("The sum of integers in T1 must be greater than zero.")

    random_list = [random.randint(0, RANGE) for _ in range(list_size)]

    mean = statistics.mean(random_list)
    median = statistics.median(random_list)
    try:
        mode = statistics.mode(random_list)
    except statistics.StatisticsError as e:
        raise statistics.StatisticsError("No unique mode found in the generated list.") from e

    return (mean, median, mode)

