import os
import shutil
from glob import glob
def task_func(src_folder, dst_folder):
    if not os.path.exists(src_folder):
        return {
            'success': False,
            'message': f"Source folder '{src_folder}' does not exist.",
            'failed_files': []
        }

    if not os.path.exists(dst_folder):
        try:
            os.makedirs(dst_folder)
        except OSError as e:
            return {
                'success': False,
                'message': f"Failed to create destination folder '{dst_folder}': {e}",
                'failed_files': []
            }

    failed_files = []
    all_files = glob(os.path.join(src_folder, '*'))
    for file_path in all_files:
        if os.path.isfile(file_path):
            try:
                compressed_file_path = file_path + ".gz"
                subprocess.run(['gzip', file_path], check=True, capture_output=True)

                file_name = os.path.basename(compressed_file_path)
                dst_file_path = os.path.join(dst_folder, file_name)
                shutil.move(compressed_file_path, dst_file_path)

            except subprocess.CalledProcessError as e:
                failed_files.append(os.path.basename(file_path))
                print(f"Error compressing or moving file '{file_path}': {e.stderr.decode()}")
            except Exception as e:
                failed_files.append(os.path.basename(file_path))
                print(f"Unexpected error processing file '{file_path}': {e}")

    if not failed_files:
        return {
            'success': True,
            'message': f"Successfully compressed and moved all files from '{src_folder}' to '{dst_folder}'.",
            'failed_files': []
        }
    else:
        return {
            'success': False,
            'message': f"Failed to compress or move some files. See 'failed_files' for details.",
            'failed_files': failed_files
        }

