import subprocess
import os
import shutil
from glob import glob
def task_func(src_folder, dst_folder):
    result = {
        'success': True,
        'message': 'All files were compressed and moved successfully.',
        'failed_files': []
    }

    if not os.path.exists(src_folder):
        result['success'] = False
        result['message'] = f"Source folder '{src_folder}' does not exist."
        return result
    if not os.path.exists(dst_folder):
        os.makedirs(dst_folder)

    files = glob(os.path.join(src_folder, '*'))

    for file in files:
        filename = os.path.basename(file)
        if os.path.isdir(file):
            continue

        try:
            subprocess.run(['gzip', '-f', file], check=True)
        except subprocess.CalledProcessError as e:
            result['success'] = False
            result['message'] = f"Failed to compress file '{filename}'."
            result['failed_files'].append(filename)
            continue

        compressed_file = file + '.gz'
        try:
            shutil.move(compressed_file, dst_folder)
        except Exception as e:
            result['success'] = False
            result['message'] = f"Failed to move compressed file '{filename}.gz'."
            result['failed_files'].append(filename)
            os.remove(compressed_file)

    if result['failed_files']:
        result['message'] = f"Failed to compress or move {len(result['failed_files'])} files."

    return result

