def task_func(f):
    func_info = {}
    func_info['name'] = f.__name__
    func_info['is_lambda'] = isinstance(f, types.LambdaType)

    signature = inspect.signature(f)
    func_info['arguments'] = {}
    for name, param in signature.parameters.items():
        arg_info = {}
        arg_info['annotation'] = param.annotation if param.annotation != inspect.Parameter.empty else None
