import collections
def task_func(vegetable_dict, seed=0):
    random.seed(seed)

    vegetable_to_people = collections.defaultdict(list)
    for person, vegetables in vegetable_dict.items():
        for vegetable in vegetables:
            vegetable_to_people[vegetable].append(person)

