        for vegetable, count in vegetable_counts.items()
    }

    df = pd.DataFrame(
        list(vegetable_counts.items()), columns=["Vegetable", "Count"]
    )
    df["Percentage"] = df["Vegetable"].map(vegetable_percentages)

    return df

