    distances = {}
    for name1 in dic:
        for name2 in dic:
            if name1 != name2:
                loc1 = dic[name1]
                loc2 = dic[name2]
                pair = tuple(sorted([name1, name2]))
                distances[pair] = geodesic(loc1, loc2).km

    return m, distances

