import re
import pandas as pd
STOPWORDS = ["Those", "are", "the", "words", "to", "ignore"]
def task_func(text):
    sentences = re.split(r'(?<!\w\.\w.)(?<![A-Z][a-z]\.)(?<=\.|\?)\s', text)
    sentence_word_counts = {}
    sentence_index = 1

    for sentence in sentences:
        if sentence.strip():                        
            words = sentence.split()
            word_count = 0
            for word in words:
                if word not in STOPWORDS:
                    word_count += 1
            sentence_word_counts[f"Sentence {sentence_index}"] = word_count
            sentence_index += 1

    return pd.Series(sentence_word_counts)

