import re
from pathlib import Path
import tarfile
PATTERN = r"(?<!Distillr)\\\\AcroTray\.exe"
DIRECTORY = r"C:\\SomeDir\\"
def task_func(directory=DIRECTORY, file_pattern=PATTERN):
    target_dir = Path(directory)
    if not target_dir.is_dir():
        print(f"Error: Directory '{directory}' does not exist.")
        return None

    matching_files = []
    for file_path in target_dir.rglob("*"):
        if file_path.is_file() and re.search(file_pattern, str(file_path)):
            matching_files.append(file_path)

    if not matching_files:
        print(f"No files matching pattern '{file_pattern}' found in '{directory}'.")
        return None

    tar_file_path = Path(directory) / "archived_files.tar.gz"
    with tarfile.open(tar_file_path, "w:gz") as tar:
        for file_path in matching_files:
            tar.add(file_path, arcname=file_path.name)

    return str(tar_file_path)

import json
import csv
def task_func(json_file, csv_file):
    try:
        with open(json_file, 'r') as f:
            data = json.load(f)
    except FileNotFoundError:
        return "Error: JSON file not found."
    except json.JSONDecodeError:
        return "Error: Invalid JSON format."

    if not isinstance(data, list):
        return "Error: JSON data must be a list of objects."

    if not data:
        with open(csv_file, 'w', newline='') as f:
            return csv_file


    try:
        with open(csv_file, 'w', newline='') as f:
            writer = csv.writer(f)

            header = list(data[0].keys())
            writer.writerow(header)

            for row in data:
                writer.writerow(row.values())
    except Exception as e:
        return f"Error writing CSV file: {e}"

    return csv_file

import re
import os
import shutil
def task_func(source_dir, target_dir, file_pattern=r'\b[A-Za-z0-9]+\.(txt|doc|docx)\b'):
    if not os.path.exists(source_dir):
        raise FileNotFoundError("The source directory does not exist.")
    if not os.path.exists(target_dir):
        os.makedirs(target_dir)

    moved_files_count = 0

    for filename in os.listdir(source_dir):
        if re.match(file_pattern, filename):
            shutil.move(os.path.join(source_dir, filename), os.path.join(target_dir, filename))
            moved_files_count += 1

    return moved_files_count

