def task_func(source_dir, target_dir, file_pattern=r'(?<!Distillr)\\AcroTray\.exe'):
    if not os.path.exists(target_dir):
        os.makedirs(target_dir)

    pattern = re.compile(file_pattern)

    matching_files = []

    for root, _, files in os.walk(source_dir):
        for file in files:
