import ast
import re
def task_func(text_file: str) -> list:
    try:
        with open(text_file, 'r') as f:
            text = f.read()
    except FileNotFoundError:
        return []

    dict_strings = re.findall(r'\{[\s\S]*?\}', text)

    result = []
    for dict_str in dict_strings:
        try:
            result.append(ast.literal_eval(dict_str))
        except (ValueError, SyntaxError):
            continue
    return result

import ast
import re
def task_func(text_file: str) -> list:
    extracted_dicts = []

    dict_pattern = r'\{.*?\}'

    with open(text_file, 'r') as file:
        content = file.read()

    matches = re.findall(dict_pattern, content)

    for match in matches:
        try:
            parsed_dict = ast.literal_eval(match)
            if isinstance(parsed_dict, dict):
                extracted_dicts.append(parsed_dict)
        except (ValueError, SyntaxError):
            continue

    return extracted_dicts

import ast
import re
def task_func(text_file: str) -> list:
