    ax = sns.heatmap(heatmap_data, annot=True, fmt=".1f", cmap="coolwarm", cbar_kws={'label': 'Temperature'})
    plt.title("Temperature Heatmap")
    plt.xlabel("Time")
    plt.ylabel("Date")
    plt.tight_layout()

    return ax

