import re
from faker import Faker
import random
def task_func(epoch_milliseconds, seed=0, timezones=["UTC"]):
    faker = Faker()
    Faker.seed(seed)
    random.seed(seed)

    epoch_seconds = epoch_milliseconds / 1000
    local_datetime = datetime.fromtimestamp(epoch_seconds)

