            if sign == "-":
                offset = -offset
            timezone = pytz.FixedOffset(offset)
            localized_datetime = local_datetime.astimezone(timezone)

    event_name = faker.sentence(nb_words=3).strip(".")

    event_date = localized_datetime.strftime("%Y-%m-%d")
    event_time = localized_datetime.strftime("%H:%M:%S")

    event_schedule = {
        "date": event_date,
        "time": event_time,
        "timezone": selected_timezone
    }

    return {event_name: [event_schedule]}

