def task_func(data_list, seed=0):
    random.seed(seed)

    def replace_random_substring(s):
        parts = s.split(',')

        if len(parts) > 1:
            random_index = random.randint(0, len(parts) - 1)
        else:
            random_index = 0

        chosen_part = parts[random_index]
        length = len(chosen_part)

        random_string = ''.join(random.choices(string.ascii_lowercase, k=length))

        parts[random_index] = random_string

        return ','.join(parts)

    modified_strings = [replace_random_substring(s) for s in data_list]

    df = pd.DataFrame({
        'Original String': data_list,
        'Modified String': modified_strings
    })

    return df

