import pandas as pd
def task_func(data_list, seed=0):
    random.seed(seed)                                    

    original_strings = []
    modified_strings = []

    for s in data_list:
        substrings = []
        start = 0
        for end in range(len(s)):
            if s[end] == ',':
                substrings.append(s[start:end])
                start = end + 1
        substrings.append(s[start:])                          

        replace_idx = random.randint(0, len(substrings) - 1)
        replace_substring = substrings[replace_idx]

        random_substring = ''.join(random.choice(string.ascii_lowercase) for _ in range(len(replace_substring)))

        modified_s = ''
        for i, substring in enumerate(substrings):
            if i == replace_idx:
                modified_s += random_substring
            else:
                modified_s += substring
            if i < len(substrings) - 1:
                modified_s += ','

        original_strings.append(s)
        modified_strings.append(modified_s)

    return pd.DataFrame({'Original String': original_strings, 'Modified String': modified_strings})
