def _search_json(data, string):
    if isinstance(data, dict):
        for value in data.values():
            if _search_json(value, string):
                return True
    elif isinstance(data, list):
        for item in data:
            if _search_json(item, string):
                return True
    elif isinstance(data, str):
        if data == string:
            return True
    return False

