import ctypes
import os
import shutil
import glob
def task_func(filepath, destination_dir):
    if not os.path.isfile(filepath):
        raise FileNotFoundError(f"The specified file does not exist: {filepath}")

    if not os.path.exists(destination_dir):
        os.makedirs(destination_dir)

    try:
        dll = ctypes.CDLL(filepath)
    except Exception as e:
        raise RuntimeError(f"Failed to load DLL: {filepath}. Error: {e}")

    source_dir = os.path.dirname(filepath)

    dll_files = glob.glob(os.path.join(source_dir, "*.dll"))

    for dll_file in dll_files:
        try:
            shutil.move(dll_file, destination_dir)
        except Exception as e:
            raise RuntimeError(f"Failed to move file {dll_file} to {destination_dir}. Error: {e}")

    return os.path.basename(filepath)

