def task_func(directory):
    moved_files = {}
    if not os.path.isdir(directory):
        return directory, moved_files

    for filename in os.listdir(directory):
        if os.path.isfile(os.path.join(directory, filename)):
            match = re.search(r'[^\[\]]+', filename)
            if match:
                first_text = match.group(0).strip()
                subdir_path = os.path.join(directory, first_text)
                if not os.path.exists(subdir_path):
                    os.makedirs(subdir_path)
                    moved_files[first_text] = []

                source_path = os.path.join(directory, filename)
                dest_path = os.path.join(subdir_path, filename)
                shutil.move(source_path, dest_path)
                moved_files[first_text].append(filename)
    return directory, moved_files

